import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    best_node = None
    best_score = np.inf

    for i, customer in enumerate(unvisited_customers):
        distance_to_node = np.linalg.norm(cur_truck_pos - customer)
        node_reach = 0
        avg_other_trucks_distance = 0
        contested_weight = 0

        for other_customer in unvisited_customers:
            if not np.array_equal(customer, other_customer):
                distance_to_other = np.linalg.norm(customer - other_customer)
                if distance_to_node + np.linalg.norm(other_customer - depot_pos) < distance_to_other:
                    node_reach += 1

        for truck_pos in all_truck_pos:
            if not np.array_equal(cur_truck_pos, truck_pos):
                avg_other_trucks_distance += np.linalg.norm(truck_pos - customer)

        if len(all_truck_pos) > 1:
            avg_other_trucks_distance /= (len(all_truck_pos) - 1)

        contested_weight = distance_to_node / (avg_other_trucks_distance + 1e-6)
        score = distance_to_node - node_reach + contested_weight

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
